namespace ContosoUniversity.Tests.Models
{
    public class CourseTests
    {
        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        [Fact]
        public void ValidCourse_NoValidationErrors()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        [Fact]
        public void Title_TooShort_ValidationError()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };
            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Title_TooLong_ValidationError()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('A', 51),
                Credits = 3,
                DepartmentID = 1
            };
            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Credits_BelowRange_ValidationError()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = -1,
                DepartmentID = 1
            };
            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Credits_AboveRange_ValidationError()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = 6,
                DepartmentID = 1
            };
            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Theory]
        [InlineData(0)]
        [InlineData(3)]
        [InlineData(5)]
        public void Credits_InRange_NoValidationError(int credits)
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = credits,
                DepartmentID = 1
            };
            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        [Fact]
        public void Course_HasNavigationProperties()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                Department = new Department { Name = "Engineering" },
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.NotNull(course.Department);
            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
        }

        [Fact]
        public void TeachingMaterialImagePath_MaxLength255()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = new string('A', 256)
            };
            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("TeachingMaterialImagePath"));
        }
    }
