using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class DepartmentTests
    {
        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        [Fact]
        public void ValidDepartment_NoValidationErrors()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            var results = ValidateModel(dept);
            Assert.Empty(results);
        }

        [Fact]
        public void Name_TooShort_ValidationError()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Today
            };
            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Name_TooLong_ValidationError()
        {
            var dept = new Department
            {
                Name = new string('A', 51),
                Budget = 100000,
                StartDate = DateTime.Today
            };
            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void InstructorID_Nullable()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000,
                StartDate = DateTime.Today,
                InstructorID = null
            };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_HasCoursesCollection()
        {
            var dept = new Department
            {
                Courses = new List<Course>
                {
                    new Course { CourseID = 1, Title = "Chemistry" },
                    new Course { CourseID = 2, Title = "Physics" }
                }
            };
            Assert.Equal(2, dept.Courses.Count);
        }

        [Fact]
        public void Department_HasAdministratorNavigation()
        {
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Smith" };
            var dept = new Department
            {
                Name = "English",
                Administrator = instructor,
                InstructorID = 1
            };
            Assert.NotNull(dept.Administrator);
            Assert.Equal("Kim", dept.Administrator.FirstMidName);
        }
    }
}

