using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class InstructorTests
    {
        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        [Fact]
        public void ValidInstructor_NoValidationErrors()
        {
            var instructor = new Instructor
            {
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = DateTime.Parse("1995-03-11")
            };
            var results = ValidateModel(instructor);
            Assert.Empty(results);
        }

        [Fact]
        public void HireDate_Required()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John"
            };
            // HireDate defaults to DateTime.MinValue which is outside the Range
            var results = ValidateModel(instructor);
            Assert.Contains(results, r => r.MemberNames.Contains("HireDate"));
        }

        [Fact]
        public void Instructor_HasCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 1 },
                    new CourseAssignment { CourseID = 2 }
                }
            };
            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void Instructor_HasOfficeAssignment()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Today,
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                ID = 5,
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Today
            };
            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Doe, Jane", instructor.FullName);
            Assert.Equal(5, instructor.ID);
        }
    }
}

