        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValuesValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_HasCourseNavigation()
        {
            var enrollment = new Enrollment
            {
                Course = new Course { CourseID = 1050, Title = "Chemistry" }
            };
            Assert.NotNull(enrollment.Course);
            Assert.Equal("Chemistry", enrollment.Course.Title);
        }

        [Fact]
        public void Enrollment_HasStudentNavigation()
        {
            var enrollment = new Enrollment
            {
                Student = new Student { FirstMidName = "John", LastName = "Doe" }
            };
            Assert.NotNull(enrollment.Student);
            Assert.Equal("Doe, John", enrollment.Student.FullName);
        }
    }
}

