using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        private static List<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        [Fact]
        public void ValidNotification_NoValidationErrors()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Empty(results);
        }

        [Fact]
        public void EntityType_Required()
        {
            var notification = new Notification
            {
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
        }

        [Fact]
        public void EntityId_Required()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityId"));
        }

        [Fact]
        public void Operation_Required()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Message = "Test",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("Operation"));
        }

        [Fact]
        public void Message_Required()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("Message"));
        }

        [Fact]
        public void EntityType_MaxLength100()
        {
            var notification = new Notification
            {
                EntityType = new string('A', 101),
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
        }

        [Fact]
        public void Message_MaxLength256()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = new string('A', 257),
                CreatedAt = DateTime.Now
            };
            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("Message"));
        }

        [Fact]
        public void IsRead_DefaultsFalse()
        {
            var notification = new Notification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void ReadAt_IsNullable()
        {
            var notification = new Notification();
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }
}

