using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                Directory.Delete(_tempDir, true);
            }
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;
            var model = result.Model as System.Collections.Generic.List<Course>;

            Assert.NotNull(model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void Index_IncludesDepartment()
        {
            var result = _controller.Index() as ViewResult;
            var model = result.Model as System.Collections.Generic.List<Course>;

            // InMemory provider supports Include
            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;
            var course = result.Model as Course;

            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(course.Department);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithDepartments()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_SavesInDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Database Design",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null);
            Assert.True(_context.Courses.Any(c => c.CourseID == 8888));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1, DepartmentID = 1 };

            var result = _controller.Create(course, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_WithValidImage_UploadsFile()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Art History",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, fileMock.Object);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var savedCourse = _context.Courses.Find(7777);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit((int?)1050) as ViewResult;
            var course = result.Model as Course;

            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit((int?)9999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            course.Title = "Advanced Chemistry";

            var result = _controller.Edit(course, null);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _controller.Edit(course, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsView()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.txt");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_WithOversizedFile_ReturnsView()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.png");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024);

            var result = _controller.Edit(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;
            var course = result.Model as Course;

            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var countBefore = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(countBefore - 1, _context.Courses.Count());
        }

        // --- Image Extension Tests ---

        [Theory]
        [InlineData("test.jpg")]
        [InlineData("test.jpeg")]
        [InlineData("test.png")]
        [InlineData("test.gif")]
        [InlineData("test.bmp")]
        public void Create_Post_AllowedExtensions_Succeeds(string fileName)
        {
            var course = new Course
            {
                CourseID = int.Parse("100" + fileName.GetHashCode().ToString().Substring(0, 1).Replace("-", "0")),
                Title = $"Course for {fileName}",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<RedirectToActionResult>(result);
        }
    }
}

