using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model);
            Assert.NotNull(model.Instructors);
            Assert.True(model.Instructors.Count() > 0);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Instructor 3 (Roger Harui) has course assignments
            var result = _controller.Index(3, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Count() > 0);
        }

        [Fact]
        public void Index_WithInstructorAndCourseId_PopulatesEnrollments()
        {
            // Instructor 3 teaches course 1050 which has enrollments
            var result = _controller.Index(3, 1050) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            var names = model.Instructors.Select(i => i.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n), names);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;
            var instructor = result.Model as Instructor;

            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithCoursesPopulated()
        {
            var result = _controller.Create() as ViewResult;
            var model = result.Model as Instructor;

            Assert.NotNull(model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var result = _controller.Create(instructor, null);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesInDatabase()
        {
            var instructor = new Instructor
            {
                LastName = "SaveTest",
                FirstMidName = "Instructor",
                HireDate = DateTime.Parse("2020-01-15")
            };

            _controller.Create(instructor, null);
            Assert.True(_context.Instructors.Any(i => i.LastName == "SaveTest"));
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "CourseTest",
                FirstMidName = "Instructor",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var result = _controller.Create(instructor, new[] { "1050", "1045" });
            Assert.IsType<RedirectToActionResult>(result);

            var saved = _context.Instructors
                .Where(i => i.LastName == "CourseTest")
                .Select(i => i.CourseAssignments.Count)
                .First();
            Assert.Equal(2, saved);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };

            var result = _controller.Create(instructor, null);
            Assert.IsType<ViewResult>(result);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;
            var instructor = result.Model as Instructor;

            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Use instructor 3 who has office assignment
            var countBefore = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(3);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(countBefore - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            // Instructor 1 is administrator of English department (DepartmentID 1)
            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }
    }
}

