using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void Context_CanCreateInMemoryDatabase()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context);
        }

        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextFactory.Create();

            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            });
            context.SaveChanges();

            Assert.Equal(1, context.Students.Count());
        }

        [Fact]
        public void Context_CanAddAndRetrieveCourse()
        {
            using var context = TestDbContextFactory.Create();

            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 100000,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            context.Courses.Add(new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            });
            context.SaveChanges();

            Assert.Equal(1, context.Courses.Count());
        }

        [Fact]
        public void Context_CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var ca = context.CourseAssignments.First();
            Assert.True(ca.CourseID > 0);
            Assert.True(ca.InstructorID > 0);
        }

        [Fact]
        public void Context_HasAllDbSets()
        {
            using var context = TestDbContextFactory.Create();

            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.People);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void Context_TPH_StudentAndInstructorSharePersonTable()
        {
            using var context = TestDbContextFactory.Create();

            context.Students.Add(new Student
            {
                FirstMidName = "Student",
                LastName = "One",
                EnrollmentDate = DateTime.Today
            });
            context.Instructors.Add(new Instructor
            {
                FirstMidName = "Instructor",
                LastName = "One",
                HireDate = DateTime.Today
            });
            context.SaveChanges();

            // Both derive from Person
            Assert.Equal(2, context.People.Count());
            Assert.Equal(1, context.Students.Count());
            Assert.Equal(1, context.Instructors.Count());
        }

        [Fact]
        public void Context_SeedData_CreatesExpectedRecords()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            Assert.Equal(3, context.Students.Count());
            Assert.Equal(3, context.Instructors.Count());
            Assert.Equal(3, context.Departments.Count());
            Assert.Equal(4, context.Courses.Count());
            Assert.Equal(3, context.Enrollments.Count());
        }

        [Fact]
        public void Context_CanQueryWithInclude()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var course = context.Courses
                .Include(c => c.Department)
                .First();

            Assert.NotNull(course.Department);
        }

        [Fact]
        public void Context_InstructorOfficeAssignment_OneToOne()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var instructor = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == 2); // Fakhouri has office

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
        }
    }
}

