    Assert.Equal("CREATE", notification.Operation);
    Assert.Equal("TestUser", notification.CreatedBy);
    Assert.False(notification.IsRead);
}

arguments.new_str:
[Fact]
public void SendNotification_CreateOperation_EnqueuesNotification()
{
    // Use a unique ID to avoid collisions with leftover notifications from parallel tests
    var uniqueId = Guid.NewGuid().ToString();
    _service.SendNotification("Student", uniqueId, EntityOperation.CREATE, "TestUser");

    // Drain until we find our notification (static queue may have others)
    Notification notification = null;
    Notification candidate;
    while ((candidate = _service.ReceiveNotification()) != null)
    {
        if (candidate.EntityId == uniqueId)
        {
            notification = candidate;
            break;
        }
    }

    Assert.NotNull(notification);
    Assert.Equal("Student", notification.EntityType);
    Assert.Equal(uniqueId, notification.EntityId);
    Assert.Equal("CREATE", notification.Operation);
    Assert.Equal("TestUser", notification.CreatedBy);
    Assert.False(notification.IsRead);
}

